import{_ as d,o as s,c as e,ag as i}from"./chunks/framework.CAXxHpAX.js";const _=JSON.parse('{"title":"辛亥革命的历史意义：推翻了清朝的统治，宣","description":"","frontmatter":{},"headers":[],"relativePath":"notes/note-31.md","filePath":"notes/note-31.md"}'),c={name:"notes/note-31.md"};function t(l,a,o,r,n,v){return s(),e("div",null,[...a[0]||(a[0]=[i('<h1 id="辛亥革命的历史意义-推翻了清朝的统治-宣" tabindex="-1">辛亥革命的历史意义：推翻了清朝的统治，宣 <a class="header-anchor" href="#辛亥革命的历史意义-推翻了清朝的统治-宣" aria-label="Permalink to &quot;辛亥革命的历史意义：推翻了清朝的统治，宣&quot;">​</a></h1><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">辛亥革命的历史意义：</span>推翻了清朝的统治，宣告两千多年的封建君主专制终结；开创了近代民族民主革命；建立了第一个资产阶级共和国——中华民国；推动近代民族工业的发展；极大推动中华民族思想解放，打开了中国进步潮流的闸门；推动了社会观念的转变和平等自由思想的普及，促使社会移风易俗。</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">局限性：</span>没有改变中国半殖民地半封建社会的性质，没有完成反帝反封建的革命任务。</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">长征胜利的意义：</span>粉碎了国民党反动派消灭红军的企图，保存了党和红军的基干力量，使中国革命转危为安，红军长征播下革命种子，铸就长征精神（独立自主、实事求是），打开了中国革命的新局面。</p></div><div class="circle-overlay"></div></div></div><div class="fx-layer"><div class="box liquid-card"><div class="card-content"><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">遵义会议：</span>1935年1月，开始确立以毛泽东为主要代表的马克思主义正确路线在中共中央的领导地位；在极其危急的情况下，挽救了党，挽救了红军，挽救了中国革命，是中共历史上一个生死攸关得转折点，是中共从幼年走向成熟的标志。</p></div><div class="circle-overlay"></div></div></div>',5)])])}const f=d(c,[["render",t]]);export{_ as __pageData,f as default};
